import sys,math
#sys.stdin=open("data.txt","r")
input=sys.stdin.readline
mii=lambda:map(int,input().split())

alpha=" !#$%&()*+,-./0123456789:;<=>?@ABCDEFGHIJKLMNOPQRSTUVWXYZ[]^_`abcdefghijklmnopqrstuvwxyz{|}~"

def makechar(d):
    return alpha[round(d*91)]

def complist(li):
    lo=min(li)
    hi=max(li)
    return (''.join(map(lambda d:makechar((d-lo)/(hi-lo)),li)),lo,hi)

def stringify(x):
    if type(x[0])==type([]): return "["+",".join(map(stringify,x))+"]"
    else: return "('%s',%.5f,%.5f)"%complist(x)

def decomp(x):
    if type(x)==type([]): return list(map(decomp,x))
    else:
        s,lo,hi=x
        return list(map(lambda c:alpha.index(c)/91.0*(hi-lo)+lo,s))


