def flatten(xx):
 y=[]
 for i in xx:
  for j in i: y+=j
 return y

def linear(x,fcw,fcb):
 n=len(x)
 y=[]
 for w,b in zip(fcw,fcb):
  for i in range(n): b+=w[i]*x[i]
  y.append(b)
 return y

def atan(x):
 return [math.atan(d) for d in x]

for n in range(int(input())):
 x=flatten([[list(map(float,input().split())) for _ in range(28)]])
 x=atan(linear(x,fcw1,fcb1))
 x=atan(linear(x,fcw2,fcb2))
 x=atan(linear(x,fcw3,fcb3))
 x=atan(linear(x,fcw4,fcb4))
 x=atan(linear(x,fcw5,fcb5))
 # get the argmax
 a,b=x[0],0
 for i in range(1,10):
  if a<x[i]: a,b=x[i],i
 print(b)
